        if (self.alt_grid == null) {
            self.alt_grid = Grid.init(self.allocator, self.grid.cols, self.grid.rows, 0);
        }
        const tmp = self.grid;
        self.grid = self.alt_grid.?;
        self.alt_grid = tmp;

